export default class KeyPair extends HTMLElement {
  static get observedAttributes() {
    return ['value'];
  }

  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    shadowRoot.innerHTML = `
      <style>
        :host {
          font-family: var(--font-family);
          font-size: 18px;
          background: var(--background-primary);
          padding: 20px;
          box-sizing: border-box;
          border-radius: 10px;
          height: 100px;
        } 
        .root {
          display: flex;
          flex-direction: row;
          justify-content: center;
        }
        .left {
          display: flex;
          flex-direction: column;
          justify-content: center;
          flex: 3;
        }
        .right {
          flex: 1; 
          display: flex;
          align-items: center;
          justify-content: center;
        }
        .value {
          font-size: 34px;
        }
        .text {
          font-size: 14px;
          color: var(--text-tertiary);
        }
      </style>
      <div class="root">
        <div class="left">
          <span class="value"></span>
          <span class="text">
            <slot></slot>
          </span>
        </div>
        <div class="right">
          <div><slot name="icon"></slot></div>
        </div>
      </div>
    `
  }

  connectedCallback() {
    this.classList.add("hydrated")
    this.render()
  }

  render = () => {
    const value = this.getAttribute("value")
    const text = this.shadowRoot.querySelector(".value")
    text.innerHTML = value
  }

  attributeChangedCallback(name, oldValue, newValue) {
    this.render()
  }
}
